import * as fs from 'node:fs';
import path from 'path';
export interface Task {
  id: string;
  title: string;
  done: boolean;
  createdAt: string;
  doneAt?: string;
}

export class TaskStore {
  private filePath: string;

  constructor(filePath: string) {
    this.filePath = filePath;
    if (!fs.existsSync(this.filePath)) {
      fs.writeFileSync(this.filePath, JSON.stringify({ tasks: [] }));
    }
  }

  list(): Task[] {
    const data = fs.readFileSync(this.filePath, 'utf8');
    return JSON.parse(data).tasks;
  }

  add(title: string): Task {
    const tasks = this.list();
    const task: Task = {
      id: uuidv4(),
      title,
      done: false,
      createdAt: new Date().toISOString()
    };
    tasks.push(task);
    fs.writeFileSync(this.filePath, JSON.stringify({ tasks }));
    return task;
  }

  done(id: string): Task {
    const tasks = this.list();
    const taskIndex = tasks.findIndex(t => t.id === id);
    if (taskIndex !== -1) {
      tasks[taskIndex].done = true;
      tasks[taskIndex].doneAt = new Date().toISOString();
      fs.writeFileSync(this.filePath, JSON.stringify({ tasks }));
    }
    return tasks[taskIndex];
  }

  remove(id: string): Task {
    const tasks = this.list();
    const taskIndex = tasks.findIndex(t => t.id === id);
    if (taskIndex !== -1) {
      const removedTask = tasks[taskIndex];
      tasks.splice(taskIndex, 1);
      fs.writeFileSync(this.filePath, JSON.stringify({ tasks }));
      return removedTask;
    }
    throw new Error('Task not found');
  }
}
"}, {"path": "src/cli.ts", "content": "import { TaskStore } from './store';
const fs = require('node:fs');
const path = require('path');
const argv = process.argv.slice(2);
let cmd = argv[0];
let dataPath = '';
if (argv.includes('--data')) {
  const index = argv.indexOf('--data') + 1;
  if (index < argv.length) {
    dataPath = argv[index];
  }
}

const store = new TaskStore(dataPath);

function help() {
  console.log(`Usage:
add <title> -- Add a new task
list --data <path> -- List tasks from the specified data file
done <id> --data <path> -- Mark a task as done
remove <id> --data <path> -- Remove a task`);
  process.exit(0);
}

if (cmd === '--help') {
  help();
} else if (cmd === 'list' && dataPath) {
  const tasks = store.list();
  console.log(JSON.stringify({ ok: true, tasks }));
} else if (cmd === 'add' && argv[1]) {
  const task = store.add(argv[1]);
  console.log(JSON.stringify({ ok: true, task }));
} else if (cmd === 'done' && argv[1]) {
  try {
    const task = store.done(argv[1]);
    console.log(JSON.stringify({ ok: true, task }));
  } catch (e) {
    console.error(e);
    process.exit(1);
  }
} else if (cmd === 'remove' && argv[1]) {
  try {
    const task = store.remove(argv[1]);
    console.log(JSON.stringify({ ok: true, task }));
  } catch (e) {
    console.error(e);
    process.exit(1);
  }
} else {
  console.error('Invalid command or missing arguments');
  help();
}"}], "notes": "optional"}
